// ============================================================
// Log Level Enum
// ============================================================
enum class LogLevel(val priority: Int) {
    VERBOSE(Log.VERBOSE),
    DEBUG(Log.DEBUG),
    INFO(Log.INFO),
    WARN(Log.WARN),
    ERROR(Log.ERROR),
    ASSERT(Log.ASSERT)
}

// ============================================================
// Log Entry Data Class
// ============================================================
data class LogEntry(
    val timestamp: Long = System.currentTimeMillis(),
    val level: LogLevel,
    val tag: String,
    val message: String,
    val throwable: Throwable? = null,
    val metadata: Map<String, Any?> = emptyMap()
) {
    fun formatted(): String {
        val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
        val sb = StringBuilder()
        sb.append("[${dateFormat.format(Date(timestamp))}]")
        sb.append(" [${level.name}]")
        sb.append(" [$tag]")
        sb.append(" $message")
        if (metadata.isNotEmpty()) {
            sb.append(" | Metadata: ${metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }}")
        }
        if (throwable != null) {
            val sw = StringWriter()
            throwable.printStackTrace(PrintWriter(sw))
            sb.append("\n  StackTrace: $sw")
        }
        return sb.toString()
    }
}

// ============================================================
// File Logging Tree for Timber
// ============================================================
class FileLoggingTree(private val context: Context) : Timber.Tree() {

    private val executor = Executors.newSingleThreadExecutor()
    private val logBuffer = ConcurrentLinkedQueue<String>()
    private val bufferFlushSize = 20
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val maxLogFiles = 7
    private val maxFileSize = 10 * 1024 * 1024L // 10MB

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val entry = LogEntry(
            level = LogLevel.entries.find { it.priority == priority } ?: LogLevel.VERBOSE,
            tag = tag ?: "UNKNOWN",
            message = message,
            throwable = t
        )
        logBuffer.add(entry.formatted())

        if (logBuffer.size >= bufferFlushSize) {
            flushBuffer()
        }
    }

    private fun flushBuffer() {
        val entries = mutableListOf<String>()
        while (logBuffer.isNotEmpty()) {
            logBuffer.poll()?.let { entries.add(it) }
        }
        if (entries.isEmpty()) return

        executor.execute {
            try {
                val logDir = File(context.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()

                val logFile = File(logDir, "app_log_${dateFormat.format(Date())}.log")

                // Rotate if file too large
                if (logFile.exists() && logFile.length() > maxFileSize) {
                    val rotatedFile = File(logDir, "app_log_${dateFormat.format(Date())}_${System.currentTimeMillis()}.log")
                    logFile.renameTo(rotatedFile)
                }

                FileWriter(logFile, true).use { writer ->
                    entries.forEach { entry ->
                        writer.appendLine(entry)
                    }
                }

                // Clean old log files
                cleanOldLogs(logDir)
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write logs to file", e)
            }
        }
    }

    private fun cleanOldLogs(logDir: File) {
        val logFiles = logDir.listFiles()?.sortedByDescending { it.lastModified() } ?: return
        if (logFiles.size > maxLogFiles) {
            logFiles.drop(maxLogFiles).forEach { it.delete() }
        }
    }

    fun flush() {
        flushBuffer()
    }
}

// ============================================================
// Verbose Debug Tree (Console)
// ============================================================
class VerboseDebugTree : Timber.DebugTree() {
    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber}) ${element.methodName}"
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val threadInfo = "[Thread:${Thread.currentThread().name}]"
        super.log(priority, tag, "$threadInfo $message", t)
    }
}

// ============================================================
// Main AppLogger - Central Logging Facade
// ============================================================
object AppLogger {

    private lateinit var fileTree: FileLoggingTree
    private var isInitialized = false

    fun initialize(context: Context) {
        if (isInitialized) return

        fileTree = FileLoggingTree(context.applicationContext)

        // Plant both console and file trees for production diagnostics
        Timber.plant(VerboseDebugTree())
        Timber.plant(fileTree)

        // Set up global uncaught exception handler
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            Timber.e(throwable, "UNCAUGHT EXCEPTION on thread ${thread.name}")
            fileTree.flush()
            defaultHandler?.uncaughtException(thread, throwable)
        }

        isInitialized = true
        Timber.v("AppLogger initialized successfully")
    }

    fun flushLogs() {
        if (isInitialized) {
            fileTree.flush()
        }
    }

    fun getLogFiles(context: Context): List<File> {
        val logDir = File(context.filesDir, "logs")
        return logDir.listFiles()?.toList()?.sortedByDescending { it.lastModified() } ?: emptyList()
    }
}

