object AuthLogger {
    private const val TAG = "AUTH"

    fun logLoginAttempt(username: String, method: String, ipAddress: String? = null) {
        Timber.tag(TAG).v(
            "Login attempt started | User: %s | Method: %s | IP: %s | Timestamp: %s",
            sanitizeUsername(username),
            method,
            ipAddress ?: "unknown",
            System.currentTimeMillis()
        )
    }

    fun logLoginSuccess(
        username: String,
        method: String,
        userId: String,
        sessionId: String,
        tokenExpiry: Long? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val metaStr = if (metadata.isNotEmpty()) {
            " | Metadata: ${metadata.entries.joinToString(", ") { "${it.key}=${it.value}" }}"
        } else ""

        Timber.tag(TAG).i(
            "LOGIN SUCCESS | User: %s | UserId: %s | Method: %s | SessionId: %s | TokenExpiry: %s%s",
            sanitizeUsername(username),
            userId,
            method,
            sessionId,
            tokenExpiry?.let { SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US).format(Date(it)) } ?: "N/A",
            metaStr
        )
    }

    fun logLoginFailure(
        username: String,
        method: String,
        reason: String,
        errorCode: Int? = null,
        exception: Throwable? = null,
        attemptNumber: Int = 0
    ) {
        Timber.tag(TAG).w(
            exception,
            "LOGIN FAILED | User: %s | Method: %s | Reason: %s | ErrorCode: %s | Attempt: %d",
            sanitizeUsername(username),
            method,
            reason,
            errorCode?.toString() ?: "N/A",
            attemptNumber
        )
    }

    fun logLogout(userId: String, sessionId: String, reason: String = "user_initiated") {
        Timber.tag(TAG).i(
            "LOGOUT | UserId: %s | SessionId: %s | Reason: %s",
            userId,
            sessionId,
            reason
        )
    }

    fun logTokenRefresh(userId: String, success: Boolean, error: Throwable? = null) {
        if (success) {
            Timber.tag(TAG).v("TOKEN REFRESH SUCCESS | UserId: %s", userId)
        } else {
            Timber.tag(TAG).w(error, "TOKEN REFRESH FAILED | UserId: %s", userId)
        }
    }

    fun logRegistrationAttempt(email: String, method: String) {
        Timber.tag(TAG).v(
            "Registration attempt | Email: %s | Method: %s",
            sanitizeEmail(email),
            method
        )
    }

    fun logRegistrationSuccess(email: String, userId: String) {
        Timber.tag(TAG).i(
            "REGISTRATION SUCCESS | Email: %s | UserId: %s",
            sanitizeEmail(email),
            userId
        )
    }

    fun logRegistrationFailure(email: String, reason: String, exception: Throwable? = null) {
        Timber.tag(TAG).w(
            exception,
            "REGISTRATION FAILED | Email: %s | Reason: %s",
            sanitizeEmail(email),
            reason
        )
    }

    fun logPasswordResetRequest(email: String, success: Boolean) {
        Timber.tag(TAG).i(
            "PASSWORD RESET REQUEST | Email: %s | Success: %s",
            sanitizeEmail(email),
            success
        )
    }

    fun logBiometricAuth(userId: String, success: Boolean, biometricType: String) {
        if (success) {
            Timber.tag(TAG).i(
                "BIOMETRIC AUTH SUCCESS | UserId: %s | Type: %s",
                userId, biometricType
            )
        } else {
            Timber.tag(TAG).w(
                "BIOMETRIC AUTH FAILED | UserId: %s | Type: %s",
                userId, biometricType
            )
        }
    }

    private fun sanitizeUsername(username: String): String {
        if (username.length <= 3) return "***"
        return "${username.take(2)}***${username.takeLast(1)}"
    }

    private fun sanitizeEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val localPart = parts[0]
        val domain = parts[1]
        val sanitizedLocal = if (localPart.length <= 2) "***" else "${localPart.take(1)}***${localPart.takeLast(1)}"
        return "$sanitizedLocal@$domain"
    }
}

